 ('42000000-0000-0000-0000-000000000801','32000000-0000-0000-0000-000000000008',1,$p$Vou fazer: ir + infinitivo$p$,$p$Vou fazer: ir + infinitivo$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000000802','32000000-0000-0000-0000-000000000008',2,$p$Vamos…? proponer planes$p$,$p$Vamos…? proponer planes$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000000803','32000000-0000-0000-0000-000000000008',3,$p$Cuándo: expresiones de tiempo futuro$p$,$p$Cuándo: expresiones de tiempo futuro$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000000804','32000000-0000-0000-0000-000000000008',4,$p$Quedar con alguien$p$,$p$Quedar con alguien$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000000805','32000000-0000-0000-0000-000000000008',5,$p$🏁 Checkpoint Unidade 8$p$,$p$Demuestra que sabes hablar de tus planes en portugués de Brasil. Usa "ir + infinitivo" (vou viajar), propón planes con "vamos…?" y "que tal…?", y maneja las expresiones de tiempo futuro (amanhã, semana que vem). El checkpoint mezcla las cuatro habilidades con frases nuevas para medir si puedes transferir lo aprendido.$p$,'checkpoint',40)
