 ('42000000-0000-0000-0000-000000001001','32000000-0000-0000-0000-000000000010',1,$p$No restaurante$p$,$p$No restaurante$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000001002','32000000-0000-0000-0000-000000000010',2,$p$Cantidades y precios$p$,$p$Cantidades y precios$p$,'lesson',15),
