 ('42000000-0000-0000-0000-000000001004','32000000-0000-0000-0000-000000000010',4,$p$Comparar: mais... que$p$,$p$Comparar: mais... que$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000001005','32000000-0000-0000-0000-000000000010',5,$p$🏁 Checkpoint Unidade 10$p$,$p$Demuestra que sabes desenvolverte en un restaurante y de compras en portugués de Brasil. Pides educadamente con "eu queria", entiendes cantidades y precios (um pouco, muito, quanto custa, reais) y comparas opciones con "mais... (do) que". Las frases y distractores son nuevos para medir transferencia, no memoria.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
