insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('42000000-0000-0000-0000-000000001201','32000000-0000-0000-0000-000000000012',1,$p$El cuerpo y el médico$p$,$p$El cuerpo y el médico$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000001202','32000000-0000-0000-0000-000000000012',2,$p$Consejos: deveria / tem que$p$,$p$Consejos: deveria / tem que$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000001203','32000000-0000-0000-0000-000000000012',3,$p$Já / nunca: experiencias$p$,$p$Já / nunca: experiencias$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000001204','32000000-0000-0000-0000-000000000012',4,$p$Há / atrás: hace cuánto$p$,$p$Há / atrás: hace cuánto$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000001205','32000000-0000-0000-0000-000000000012',5,$p$🏁 Checkpoint Unidade 12$p$,$p$En esta unidad hablas de salud: las partes del cuerpo y lo que pasa en el médico (estou com dor, o que você tem). Aprendes a dar consejos con deveria (debería) y tem que (tienes que). Cuentas experiencias con o pretérito perfeito y los marcadores já (ya) y nunca, y dices hace cuánto tiempo pasó algo usando há y atrás.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
